svgRadicalTimer(args)
{
const progress = args["progress"];
    const thickness = args["thickness"];
    const radius = args["radius"];
    const blankcolor = args["blankColor1"];
 const blankcolor2 = args["blankColor2"];
    const litcolor = args["litColor1"];
    const litcolor2 = args["litColor2"];

    const dasharray = 2 * Math.PI * radius;
    const dashoffset = dasharray - (progress / 100) * dasharray;
      const size = (radius + thickness) * (2 + 10);
      const centerpos = (size / 2);

          switch (args['withWithoutMenu']) {

case 'with': return `<svg viewBox="0 0 ${size} ${size}" xmlns="http://www.w3.org/2000/svg"><linearGradient id="blank" gradientTransform="rotate(90)"><stop offset="5%" stop-color="${blankcolor}" /><stop offset="95%" stop-color="${blankcolor2}" /></linearGradient><linearGradient id="lit" gradientTransform="rotate(0)"><stop offset="5%" stop-color="${litcolor2}" /><stop offset="95%" stop-color="${litcolor}" /></linearGradient><circle cx="${centerpos}" cy="${centerpos}" r="${radius}" fill="none" stroke="url('#blank')" stroke-width="${thickness}"/><circle cx="${centerpos}" cy="${centerpos}" r="${radius}" fill="none" stroke="url('#lit')" stroke-width="${thickness}" stroke-dasharray="${dasharray}" stroke-dashoffset="${dashoffset}" transform="rotate(-90 ${centerpos} ${centerpos})"/></svg>`;

case 'without': return `<svg viewBox="0 0 ${size} ${size}" xmlns="http://www.w3.org/2000/svg"><circle cx="${centerpos}" cy="${centerpos}" r="${radius}" fill="none" stroke="${blankcolor}" stroke-width="${thickness}"/><circle cx="${centerpos}" cy="${centerpos}" r="${radius}" fill="none" stroke="${litcolor}" stroke-width="${thickness}" stroke-dasharray="${dasharray}" stroke-dashoffset="${dashoffset}" transform="rotate(-90 ${centerpos} ${centerpos})"/></svg>`;
          
default: return "";
          }
  }

